create extension if not exists "pgcrypto";
create or replace function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at = now(); return new; end; $$;
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, email text, full_name text, role text default 'creator', created_at timestamptz default now(), updated_at timestamptz default now());
create table public.products (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, title text not null, category text, affiliate_link text not null, image_url text, price numeric, commission_rate numeric, risk_flags text[] default '{}', created_at timestamptz default now(), updated_at timestamptz default now());
create table public.review_projects (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, product_id uuid references public.products(id) on delete cascade not null, title text not null, status text not null default 'product_imported', compliance_status text, approval_status text default 'pending', has_affiliate_disclosure boolean default false, has_ai_content_label boolean default false, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.ai_briefs (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, project_id uuid references public.review_projects(id) on delete cascade not null, product_summary text, target_audience text, pain_points jsonb, key_benefits jsonb, usp text, content_angles jsonb, hook_ideas jsonb, risk_level text, creator_note text, prompt_version text not null, ai_provider text not null, ai_model text not null, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.scripts (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, project_id uuid references public.review_projects(id) on delete cascade not null, duration_seconds int not null, hook text, problem text, product_intro text, benefits jsonb, use_case text, cta text, affiliate_disclosure text, full_script text, subtitle_lines jsonb, prompt_version text not null, ai_provider text not null, ai_model text not null, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.compliance_checks (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, project_id uuid references public.review_projects(id) on delete cascade not null, status text not null, risk_score int not null, issues jsonb, prohibited_words jsonb, missing_requirements jsonb, suggested_fixes jsonb, safe_rewrite text, prompt_version text not null, ai_provider text not null, ai_model text not null, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.media_assets (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade, project_id uuid references public.review_projects(id) on delete cascade not null, type text not null, provider text default 'mock', storage_path text, metadata jsonb default '{}', created_at timestamptz default now(), updated_at timestamptz default now());
create table public.approvals (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade, project_id uuid references public.review_projects(id) on delete cascade not null, status text not null, notes text, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.posting_queue (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade, project_id uuid references public.review_projects(id) on delete cascade not null, status text not null default 'ready', scheduled_at timestamptz, published_at timestamptz, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.analytics_events (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, project_id uuid references public.review_projects(id) on delete set null, event_name text not null, properties jsonb default '{}', created_at timestamptz default now());
create table public.ai_logs (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete set null, task_type text not null, prompt_version text not null, ai_provider text not null, ai_model text not null, input_payload jsonb, output_payload jsonb, error_message text, latency_ms int, status text not null, created_at timestamptz default now());
alter table profiles enable row level security; alter table products enable row level security; alter table review_projects enable row level security; alter table ai_briefs enable row level security; alter table scripts enable row level security; alter table compliance_checks enable row level security; alter table media_assets enable row level security; alter table approvals enable row level security; alter table posting_queue enable row level security; alter table analytics_events enable row level security; alter table ai_logs enable row level security;
create policy "owner profiles" on profiles for all using (auth.uid() = id) with check (auth.uid() = id);
do $$ declare t text; begin foreach t in array array['products','review_projects','ai_briefs','scripts','compliance_checks','media_assets','approvals','posting_queue','analytics_events','ai_logs'] loop execute format('create policy "owner %I" on public.%I for all using (auth.uid() = user_id) with check (auth.uid() = user_id)', t, t); end loop; end $$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer as $$ begin insert into public.profiles(id,email,full_name) values (new.id,new.email,new.raw_user_meta_data->>'full_name'); return new; end; $$;
create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
do $$ declare t text; begin foreach t in array array['profiles','products','review_projects','ai_briefs','scripts','compliance_checks','media_assets','approvals','posting_queue'] loop execute format('create trigger set_%I_updated_at before update on public.%I for each row execute procedure public.set_updated_at()', t, t); end loop; end $$;
